import { Navigate, Outlet, useNavigate, useLocation } from 'react-router-dom';
import { createContext, ReactNode, useContext, useEffect, useState } from 'react';
import {getAuthInfo} from '../utils/authUtils';
import {defaultAlert, defaultConfirm} from "../utils/alert";

interface AuthInfo {
    memberId: string;
    memberCode: string;
    role: string;
    coordinatorCode: string;
}

const ProtectedRoute = () => {
    const navigate = useNavigate();
    const [auth, setAuth] = useState<AuthInfo | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const authInfo = getAuthInfo();
        setAuth(authInfo);
        setIsLoading(false);

        if (!authInfo) {
            defaultConfirm(
                "회원전용 서비스입니다. \n로그인 후 이용해주세요.",
                "로그인",
                "취소",
                (isConfirmed) => {
                    if (isConfirmed) {
                        navigate('/login', {replace: true});
                    } else {
                        navigate('/', {replace: true});
                    }
                }
            );
        }
    }, [navigate]);

    if (isLoading) {
        return null;
    }

    if (!auth) {
        return null;
    }

    return <Outlet context={{auth}}/>;
};

export const CoordinatorProtectedRoute = () => {
    const auth = getAuthInfo();

    if (!auth) {
        return <Navigate to="/login" replace/>;
    }
    if (auth.role !== 'ROLE_COORDINATOR') {
        defaultAlert("코디회원 전용 서비스입니다.");
        return <Navigate to="/" replace/>;
    }

    return <Outlet context={{auth}}/>;
};

export const useAuthInfo = () => {
    return getAuthInfo();
};

interface PaymentAuthContextType {
    isPaymentAuthed: boolean;
    setPaymentAuthed: (value: boolean) => void;
}

const PaymentAuthContext = createContext<PaymentAuthContextType | undefined>(undefined);

export const PaymentAuthProvider = ({children}: { children: ReactNode }) => {
    const [isPaymentAuthed, setPaymentAuthed] = useState(false);

    return (
        <PaymentAuthContext.Provider value={{isPaymentAuthed, setPaymentAuthed}}>
            {children}
        </PaymentAuthContext.Provider>
    );
};
export const usePaymentAuth = () => {
    const context = useContext(PaymentAuthContext);
    if (!context) {
        throw new Error('usePaymentAuth는 PaymentAuthProvider 내부에서 사용해야 합니다');
    }
    return context;
};

/**
 * 결제 비밀번호 입력 필수 ProtectedRoute
 * 결제 비밀번호를 입력하지 않으면 /payment-password 페이지로 리다이렉트
 */
export const PaymentPasswordRoute = () => {
    const { isPaymentAuthed } = usePaymentAuth();
    const location = useLocation();

    if (!isPaymentAuthed) {
        return (
            <Navigate
                to="/payment-password"
                replace
                state={{
                    returnPath: location.pathname,
                }}
            />
        );
    }

    return <Outlet />;
};


export default ProtectedRoute;
